INSERT INTO public.lessons (id,course_id,title,content_type,url,file_path,article_content,estimated_minutes,sort_order) VALUES
  ('a2f10900-0000-4000-8000-000000000000','a2f00000-0000-4000-8000-000000000000','確認テスト ─ 契約書の読み方','quiz',NULL,NULL,NULL,3,2),
  ('a2f20900-0000-4000-8000-000000000000','a2f00000-0000-4000-8000-000000000000','確認テスト ─ 就業規則・労務管理の実務','quiz',NULL,NULL,NULL,3,4),
  ('a2f30900-0000-4000-8000-000000000000','a2f00000-0000-4000-8000-000000000000','確認テスト ─ コンプライアンスとリスクマネジメント','quiz',NULL,NULL,NULL,3,6)
INSERT INTO public.quiz_questions (lesson_id,question,option_a,option_b,option_c,option_d,correct_option,sort_order) VALUES
('a2f10900-0000-4000-8000-000000000000','本文が定義する、契約書の本質はどれか。','うまくいかなかったときに何が起きるかを、あらかじめ決めておく文書','取引先との良好な関係を維持するための儀礼的な文書','会社の権利だけを一方的に主張するための文書','日々の業務手順を細かく定めた運用マニュアル','A',0),
('a2f10900-0000-4000-8000-000000000000','契約書を読むときに持つべき問いとして、本文が示すものはどれか。','この契約で、相手からどれだけ利益を引き出せるか','もし、これがうまくいかなかったら、この紙は自分を守ってくれるか','この雛形は、前回と同じ文面になっているか','署名欄と押印箇所が、正しく揃っているか','B',1),
('a2f10900-0000-4000-8000-000000000000','損害賠償条項の落とし穴として本文が挙げるのはどれか。','賠償の上限がなく、一方にだけ重く設定されているケース','賠償額が業界の相場より低く抑えられているケース','賠償の支払方法が現金に限定されているケース','賠償を請求できる担当者が指名されていないケース','A',2),
('a2f20900-0000-4000-8000-000000000000','本文が一行で示す、就業規則の定義はどれか。','経営が働く人を統制するための一方的な命令','会社と働く人の約束を、明文化したもの','労働基準法をそのまま書き写した法令集','現場ごとに自由に書き換えられる運用メモ','B',0),
('a2f20900-0000-4000-8000-000000000000','就業規則について本文が述べる、決定的な性質はどれか。','冊子として存在すれば、それだけで現場の行動が変わる','条文をすべて暗記して初めて意味を持つ','運用されて、初めて意味を持つ','法律が変わらない限り、内容も変わらない','C',1),
('a2f20900-0000-4000-8000-000000000000','懲戒の二つの大原則として本文が挙げるのはどれか。','迅速に、そして厳格に','文書で、そして口頭で','匿名で、そして即時に','段階的に、そして公平に','D',2),
('a2f30900-0000-4000-8000-000000000000','本文が一行で示す、コンプライアンスの本質はどれか。','規則を守ることそのものではなく、信頼を守り続ける仕組み','違反者を発見し、処罰するための監視の仕組み','ルールを増やし、規程を分厚くしていく取り組み','経営の指示を現場へ一方向に伝える連絡系統','A',0),
('a2f30900-0000-4000-8000-000000000000','リスクを評価して優先順位をつけるとき、本文が示す二つの軸はどれか。','対応にかかるコストと、担当者の人数','発生する可能性と、起きたときの影響','過去の発生件数と、経営の関心度','ルールの有無と、現場の忙しさ','B',1),
('a2f30900-0000-4000-8000-000000000000','リスクが起きたときの初動で、本文が最もやってはいけないとするのはどれか。','起きたことを、その場で記録すること','上長と関係部門に、早く上げること','「誰のせいだ」と、犯人探しから入ること','隠さず、事実をそのまま報告すること','C',2);
